script:
export const meta = {
  name: 'engagement-research-continuation',
  description: 'Continue deep research from checkpoint: adversarially verify saved claims per source, recheck refutations, synthesize cited report',
  phases: [
    { title: 'Verify', detail: 'one adversarial checker per source, all claims from that source' },
    { title: 'Recheck', detail: '2-judge panel for each refuted claim' },
    { title: 'Synthesize', detail: 'merge, rank by confidence, write cited report to disk' },
  ],
}

const claimsFile = 'C:\\Users\\Dan\\Desktop\\WebDev\\IslandLife\\research\\checkpoints\\all-claims.json'
const reportFile = 'C:\\Users\\Dan\\Desktop\\WebDev\\IslandLife\\research\\engagement-research-report.md'
const sources = [
  'https://dl.acm.org/doi/10.1145/3311350.3347180',
  'https://files01.core.ac.uk/download/pdf/301007767.pdf',
  'https://www.gamedeveloper.com/business/how-first-session-length-impacts-game-performance',
  'https://www.gamedeveloper.com/design/gdc-2012-10-tutorial-tips-from-i-plants-vs-zombies-i-creator-george-fan',
  'https://gdcvault.com/play/1019769/The-Sticky-Science-of-New',
  'https://selfdeterminationtheory.org/SDT/documents/2010_PrzybylskiRigbyRyan_ROGP.pdf',
  'https://www.academia.edu/90071060/Designing_for_compatible_narrative_with_incremental_game_mechanics',
  'https://medium.com/ironsource-levelup/the-princess-is-in-another-castle-understanding-the-player-goals-9ea6bea36dcd',
  'https://www.gdcvault.com/play/1024232/-RimWorld-Contrarian-Ridiculous-and',
  'https://www.tandfonline.com/doi/full/10.1080/0144929X.2021.1928753',
  'https://www.gdcvault.com/play/1023231/The-Gamer-s-Brain-Part',
  'https://dl.acm.org/doi/10.1145/3173574.3174195',
  'https://www.frontiersin.org/journals/virtual-reality/articles/10.3389/frvir.2022.847120/full',
  'https://www.researchgate.net/publication/225998888_The_Motivational_Pull_of_Video_Games_A_Self-Determination_Theory_Approach',
  'https://dl.acm.org/doi/fullHtml/10.1145/3491101.3519837',
  'https://www.gamedeveloper.com/game-platforms/just-one-more-turn---game-development-tips-and-tricks-from-the-creator-of-civilization-sid-meier-',
  'https://gamedesignskills.com/game-design/text-based/',
  'https://smartseries.sportspromedia.com/features/football-manager-miles-jacobson-sports-interactive-interview',
  'https://gdcvault.com/play/1014958/The-Turducken-Method-of-Game',
  'https://www.linkedin.com/pulse/ingenious-addiction-stardew-valley-abhishek-iyer',
  'https://www.tandfonline.com/doi/full/10.1080/15213269.2023.2242260',
  'https://www.gamedeveloper.com/design/deep-dive-refreshing-the-crusader-kings-iii-tutorial-mode-through-optimized-ux',
  'https://selfdeterminationtheory.org/player-experience-of-needs-satisfaction-pens/',
]
const preVerified = [
  { source: 'https://www.gamedeveloper.com/business/how-first-session-length-impacts-game-performance', note: 'Inline-verified 2026-07-03 via WebFetch: 5/6 claims SUPPORTED verbatim; the "only half return for second session" claim is a fair paraphrase of "typical return rate for subsequent first session play hovers around 50%".' },
  { source: 'https://www.gamedeveloper.com/design/deep-dive-refreshing-the-crusader-kings-iii-tutorial-mode-through-optimized-ux', note: 'Inline-verified 2026-07-03 via WebFetch: all 5 claims SUPPORTED verbatim (telemetry-retention link, completion not predictive, 67 to ~22 boxes, progressive disclosure, narrative framing).' },
  { source: 'https://selfdeterminationtheory.org/SDT/documents/2010_PrzybylskiRigbyRyan_ROGP.pdf', note: 'Two claims survived 3-0 adversarial voting in run 1 (SDT need-satisfaction model; three needs independently predict enjoyment/immersion/future play).' },
]

const shortName = (url) => url.replace(/https?:\/\/(www\.)?/, '').slice(0, 34)

const VERDICTS_SCHEMA = {
  type: 'object',
  properties: {
    source: { type: 'string' },
    accessible: { type: 'boolean' },
    verdicts: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          claim: { type: 'string', description: 'first ~150 chars of the claim text, verbatim' },
          verdict: { type: 'string', enum: ['SUPPORTED', 'REFUTED', 'UNVERIFIABLE'] },
          note: { type: 'string', description: 'one sentence: what the source text shows, or why unverifiable' },
        },
        required: ['claim', 'verdict', 'note'],
      },
    },
  },
  required: ['source', 'accessible', 'verdicts'],
}

phase('Verify')
log(`Verifying claims from ${sources.length} sources (claims file: checkpoint)`)

const perSource = await parallel(sources.map((src) => () => {
  const pre = preVerified.find((p) => p.source === src)
  const preNote = pre ? `\nPRIOR VERIFICATION CONTEXT (you may confirm quickly rather than re-litigate, but still sanity-check each claim): ${pre.note}` : ''
  return agent(
    `You are an adversarial fact-checker continuing a research verification pass from a saved checkpoint.\n\n` +
    `1. Read the file ${claimsFile} (a JSON array of {source, claim, quote}). Keep ONLY entries whose source is exactly: ${src}\n` +
    `2. Fetch that URL with WebFetch. If it is paywalled, JS-only, a video page (e.g. GDC Vault), or otherwise inaccessible, set accessible=false and adjudicate each claim ONLY on internal consistency between the claim and its saved quote: quote clearly supports claim => SUPPORTED with note 'quote-consistent, source inaccessible'; quote contradicts or does not contain the load-bearing element => UNVERIFIABLE. Never invent page content.\n` +
    `3. If accessible, actively try to REFUTE each claim against the page text. Mark SUPPORTED only if every load-bearing element (numbers, sample sizes, named attributions, causal direction) is backed by the text. Mark REFUTED only when the text contradicts the claim. Mark UNVERIFIABLE when the text neither supports nor contradicts.\n` +
    `4. Return one verdict per claim via StructuredOutput. Repeat each claim's first ~150 characters verbatim so it can be matched back.` +
    preNote,
    { label: `verify:${shortName(src)}`, phase: 'Verify', schema: VERDICTS_SCHEMA }
  )
}))

const sourceResults = perSource.filter(Boolean)
const allVerdicts = sourceResults.flatMap((r) => r.verdicts.map((v) => ({ ...v, source: r.source, accessible: r.accessible })))
const refuted = allVerdicts.filter((v) => v.verdict === 'REFUTED')
log(`Verify done: ${allVerdicts.length} verdicts — ${allVerdicts.filter((v) => v.verdict === 'SUPPORTED').length} supported, ${refuted.length} refuted, ${allVerdicts.filter((v) => v.verdict === 'UNVERIFIABLE').length} unverifiable`)

phase('Recheck')
const RECHECK_SCHEMA = {
  type: 'object',
  properties: {
    refutedStands: { type: 'boolean', description: 'true if the refutation is correct and the claim is wrong' },
    reason: { type: 'string' },
  },
  required: ['refutedStands', 'reason'],
}

let finalRefuted = []
if (refuted.length === 0) {
  log('No refutations to recheck')
} else {
  const rechecked = await parallel(refuted.map((r) => () =>
    parallel([0, 1].map((i) => () =>
      agent(
        `Second-opinion judge ${i + 1}. A fact-checker refuted this research claim:\n\nCLAIM: ${r.claim}\nSOURCE: ${r.source}\nREFUTATION NOTE: ${r.note}\n\nIndependently check: fetch the source if possible (WebFetch); also consult the saved quote for this claim in ${claimsFile}. Decide whether the refutation is correct (claim truly wrong) or overzealous (claim actually supported or merely unverifiable). Default to refutedStands=false if you cannot access enough evidence to confirm the refutation.`,
        { label: `recheck:${r.claim.slice(0, 24)}`, phase: 'Recheck', schema: RECHECK_SCHEMA }
      )
    )).then((votes) => {
      const stands = votes.filter(Boolean).filter((v) => v.refutedStands).length
      return { ...r, finalVerdict: stands >= 1 ? 'REFUTED' : 'UNVERIFIABLE' }
    })
  ))
  finalRefuted = rechecked.filter(Boolean).filter((x) => x.finalVerdict === 'REFUTED')
  log(`Recheck done: ${finalRefuted.length} of ${refuted.length} refutations stand`)
}

phase('Synthesize')
const refutedKeys = new Set(finalRefuted.map((r) => r.claim))
const verdictSummary = allVerdicts.map((v) => ({
  claim: v.claim,
  source: v.source,
  verdict: refutedKeys.has(v.claim) ? 'REFUTED' : (v.verdict === 'REFUTED' ? 'UNVERIFIABLE' : v.verdict),
  accessible: v.accessible,
}))

const synthesis = await agent(
  `You are the synthesis stage of a deep-research workflow on: "What evidence-backed design elements make games compelling and habit-forming — engagement, retention, and 'one more turn' compulsion — and how do they apply to a slow-paced, text/narrative-heavy, single-player economic life simulation that hides all numbers and stats behind prose?"\n\n` +
  `INPUTS:\n1. Read ${claimsFile} — the full set of 164 extracted claims with verbatim quotes and source URLs.\n2. Verification verdicts (JSON below). Treat SUPPORTED from an accessible source as [VERIFIED]; SUPPORTED from an inaccessible source as [QUOTE-CONSISTENT]; UNVERIFIABLE as [ATTRIBUTED]; drop REFUTED claims entirely.\n\nVERDICTS:\n${JSON.stringify(verdictSummary)}\n\n` +
  `TASK: Write a comprehensive, readable research report in Markdown to ${reportFile} (use the Write tool). Structure:\n` +
  `# What Makes a Game Addictive — Verified Research Findings\n` +
  `1. **Motivation psychology** — SDT need satisfaction (competence/autonomy/relatedness), need frustration vs satisfaction, variable-ratio reinforcement, flow, appointment/return loops, endowed progress, loss aversion, sunk cost.\n` +
  `2. **Design patterns from named titles** — Civilization/Sid Meier, Stardew Valley, RimWorld, Football Manager, Crusader Kings III, idle/incremental games, text games (A Dark Room, Fallen London).\n` +
  `3. **The first session** — churn statistics, session-length benchmarks, tutorial/onboarding evidence, progressive disclosure, goal-reveal ordering.\n` +
  `4. **Retention structures** — goal layering (short/medium/long), session-end hooks, nested compulsion loops, meta-progression, streaks.\n` +
  `5. **The ethical boundary** — what makes the same mechanic healthy vs a dark pattern (consent, punishment vs bonus, tuning, vulnerable players; the adolescent-cohort evidence; idle games' non-punitive model).\n` +
  `6. **Application to a numberless narrative economic life-sim** — synthesize sections 1-5 into concrete implications for such a game.\n\n` +
  `Rules: merge near-duplicate claims (the file contains several restatements — combine them). Every finding cites its source URL inline. Tag each finding [VERIFIED], [QUOTE-CONSISTENT], or [ATTRIBUTED]. Where evidence conflicts, say so. Note explicitly that F2P mobile churn statistics may not transfer to premium single-player games. End with a one-page 'Design implications checklist' of actionable principles ranked by strength of evidence. Aim for thorough but readable — roughly 2500-4000 words.\n\n` +
  `Return a 10-line executive summary of the report as your final message.`,
  { label: 'synthesize-report', phase: 'Synthesize' }
)

return {
  verdictCounts: {
    total: allVerdicts.length,
    supported: verdictSummary.filter((v) => v.verdict === 'SUPPORTED').length,
    unverifiable: verdictSummary.filter((v) => v.verdict === 'UNVERIFIABLE').length,
    refuted: finalRefuted.length,
  },
  refutedClaims: finalRefuted.map((r) => r.claim),
  reportFile,
  executiveSummary: synthesis,
}
